sections.example:
fn main() {
    let val: Option<i32> = Some(42);
    let empty: Option<i32> = None;

    println!("{}", val.unwrap_or(0));    // 42
    println!("{}", empty.unwrap_or(0));  // 0

    if let Some(x) = val {
        println!("Got: {}", x);  // Got: 42
    }

    match empty {
        Some(x) => println!("Value: {}", x),
        None => println!("Nothing here"),  // Nothing here
    }
}

