    let x = 5;
    let x = x + 1;       // shadowed, now 6
    let x = x as f64;    // shadowed, now 6.0
    println!("{}", x);   // 6

    const MOD: i64 = 1_000_000_007;
    println!("{}", MOD);  // 1000000007
    println!("{}", i32::MAX);  // 2147483647
}

